INSERT IGNORE INTO `students` (`id`, `user_id`, `name`, `name_jp`, `birthday`, `blood_type`, `height`, `hometown`, `school_year`, `rank`, `vocal`, `dance`, `visual`, `bio`, `theme_primary_color`, `theme_secondary_color`, `producer_id`, `created_at`, `updated_at`) VALUES
(1, 5, 'Saki Hanami', '花海 咲季', '2000-04-02', 'A', 152, 'Aichi', 'Class 1-1', 'Debut', 75, 75, 80, 'A new student who topped the entrance exam and a fierce ex-athlete with an unshakeable hatred of losing. A child prodigy since youth—quick to learn, skilled at everything she tries. She\'s extremely close with her younger sister Ume Hanami, but they\'re also lifelong rivals who have competed in every sport imaginable. Saki rates Ume\'\'s talent higher than anyone else\'s and fears it.\r\n', '#E30F25', '#FAD0D4', 1, '2026-05-26 13:13:20', '2026-05-27 15:57:18'),
(2, 6, 'Temari Tsukimura', '月村 手毬', '2000-06-03', 'AB', 162, 'Kyoto', 'Class 1-1', 'Debut', 75, 65, 55, 'A former elite middle-school idol, once called the #1 idol of her grade. Appears cool, stoic, and sarcastic on the surface but is secretly a lazy, spoiled troublemaker—a girl with two sides. She aims for the top to break away from the self she dislikes and learn to love herself. ', '#0C7BBB', '#CEE5F1', 1, '2026-05-26 13:13:20', '2026-06-03 15:32:22'),
(3, 7, 'Kotone Fujita', '藤田 ことね', '2000-04-29', 'O', 156, 'Saitama', 'Class 1-1', 'Debut', 65, 55, 75, 'A greedy girl who dreams of becoming \"an idol who can make money.\" She sees idol work as her one shot at turning her life around. Her grades are poor and her self-esteem is low overall, but she has full confidence in her cute face. She\'s a little uncomfortable around the student council president Sena, who keeps overestimating her for some reason.\r\n', '#F8C112', '#FEF3CF', 1, '2026-05-26 13:13:20', '2026-05-27 16:47:09'),
(4, 8, 'Lilja Katsuragi', '葛城 リーリヤ', '2000-07-24', 'B', 161, 'Sweden', 'Class 1-1', 'Debut', 55, 55, 65, 'An exchange student from overseas with no prior singing or dancing experience, who is always shrinking back as if she had no confidence. She doesn\'t look talented at first glance, but her admiration for idols is genuine, and she is an incredibly hard worker. Her father is Japanese, so she speaks the language fluently. She has a promise with her best friend Sumika to stand on the same stage together one day—the reason she enrolled at Hatsuboshi Academy. ', '#7DC4D4', '#EAFDFF', 1, '2026-05-28 17:43:41', '2026-05-28 17:56:05'),
(5, 9, 'Sumika Shiun', '紫雲 清夏', '2000-11-11', 'O', 168, 'Hokkaido', 'Class 1-1', 'Debut', 65, 55, 65, 'A laid-back gyaru who skips class and lessons—a bit of an unserious slacker, but genuinely bright, cheerful, and able to get along with anyone, which is her real charm. She once had a celebrated ballet career and was expected to go far on the world stage, but she has no motivation for it anymore. She wholeheartedly cheers on her best friend Lilja, who is earnestly chasing her idol dream. ', '#7CFC00', '#D6FFB3', 1, '2026-05-28 17:43:41', '2026-05-28 17:58:33'),
(6, 10, 'Hiro Shinosawa', '篠澤 広', '2000-12-21', 'AB', 159, 'Akita', 'Class 1-2', 'Debut', 55, 55, 60, 'A mysterious genius girl. Dissatisfied with days that are too easy and boring, she enrolled at Hatsuboshi Academy specifically to challenge her weakest areas. A true eccentric who finds joy in \"harsh, painful lessons\" and \"things that don\'t go well.\" Her reason for becoming an idol is \"because it seems like the thing I\'d be worst at.\" Despite her brilliant mind, she has extreme stamina and muscle deficits—even basic lessons leave her unsteady on her feet.\r\n', '#00AFCC', '#BFEAF2', 1, '2026-05-28 17:43:41', '2026-05-28 17:58:33'),
(7, 11, 'China Kuramoto', '倉本 千奈', '2000-08-01', 'O', 148, 'Kanagawa', 'Class 1-2', 'Debut', 55, 55, 60, 'A genuine, spoiled-rotten young lady (お嬢様) raised with every privilege. A cheerful, innocent girl who enrolled at Hatsuboshi dreaming of becoming \"a proper, splendid idol.\" Her actual ability level, by her own admission, is \"definitely dead last among the entire student body!\" Her sheltered upbringing has left her sweet, polite, and earnest—but completely behind her classmates in raw skill, which she takes in stride with her trademark \"Well then, I\'ll just have to do my best, won\'t I!\" attitude.\r\n', '#F68B1F', '#FCE0C5', 1, '2026-05-28 17:43:41', '2026-06-03 11:45:32'),
(8, 12, 'Ume Hanami', '花海 佑芽', '2000-04-01', 'AB', 158, 'Aichi', 'Class 1-2', 'Debut', 50, 60, 60, '\'A supplementary-entry new student. Energetic to the core, with exceptional physical ability from her background as a former athlete. She absolutely adores her older sister Saki — she respects her with all her heart, treats her as her ultimate rival, and holds her up as the goal she\'s aiming for. Through Saki\'s devoted support, Ume gradually blossoms her own idol talent. \r\n', '#EA533A', '#FAD4CB', 1, '2026-05-28 17:43:41', '2026-05-28 17:58:33'),
(9, 13, 'Misuzu Hataya', '秦谷 美鈴', '2000-02-06', 'B', 160, 'Kyoto', 'Class 1-2', 'Debut', 65, 70, 80, 'A languid, easygoing girl who moves at her own pace. Sweet and indulgent to both herself and others, she loves taking care of people and spoiling them. Her childhood friend Temari Tsukimura — whom she calls \"Mari-chan\" — she treats like a little sister or daughter she needs to cherish and protect. A Kyoto native and former member of the elite middle-school unit \"SyngUp!\" alongside Temari. Sleeps constantly — at every opportunity.\r\n', '#7A99CF', '#D8E0EF', 1, '2026-05-28 17:43:41', '2026-05-28 17:58:33'),
(10, 14, 'Mao Arimura', '有村 麻央', '2000-01-18', 'A', 157, 'Hyogo', 'Class 3-1', 'Debut', 75, 65, 55, 'A 3rd-year girl aiming to be a cool idol. She serves as the dormitory leader of Hatsuboshi Academy\'s idol department and is very caring. She is adored by her juniors as the \"Little Prince.\" She has a past of aspiring to be a stage musical star since childhood and working as a child actress.', '#7F1184', '#DCC2DE', 1, '2026-06-03 13:03:10', '2026-06-04 09:53:18'),
(11, 15, 'Rinami Himesaki', '姫崎 莉波', '2000-03-05', 'A', 166, 'Fukuoka', 'Class 3-1', 'Debut', 60, 70, 55, 'A mature-feeling 3rd-year student. Reliable, gentle, and caring—the big sister of everyone in the dorm. She was once part of a unit, but the results were not great. She is a member of the student council, serving as secretary.', '#F6ADC6', '#FCE6EE', 1, '2026-06-03 13:03:10', '2026-06-04 09:53:06'),
(12, 16, 'Sena Juo', '十王 星南', '2000-12-07', 'A', 170, 'Tokyo', 'Class 3-1', 'Debut', 130, 100, 105, 'Student council president of Hatsuboshi Academy. Known as \"the academy\'s top idol,\" admired by many students. The granddaughter of the academy principal, she was raised with elite idol education from a young age. She has a special ability to spot idol talent and immediately takes a liking to Kotone—but for some reason, Kotone keeps her distance.', '#F6AE54', '#FCE6CC', 1, '2026-06-03 13:03:10', '2026-06-04 09:56:40'),
(13, 17, 'Tsubame Amaya', '雨夜 燕', '2000-05-20', 'A', 169, 'Tokyo', 'Class 3-1', 'Debut', 80, 90, 70, 'Vice president of the Hatsuboshi Academy student council. The academy\'s No. 2 idol. She carries pride befitting her ability and holds herself with an arrogant attitude. She is strict with both herself and others but is caring. She sees her childhood friend Sena as a rival and has publicly declared that she will one day surpass Sena to become the \"number one star.\"', '#7B68EE', '#D8D2FB', 1, '2026-06-03 13:03:10', '2026-06-04 09:58:27');
INSERT IGNORE INTO `songs` (`id`, `title`, `title_jp`, `artist`, `duration`, `release_date`, `notes`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'Fighting My Way', 'Fighting My Way', 'Saki Hanami', '00:03:21', '2024-05-16', 'Saki Hanami\'s debut solo song. Lyrics: HIROMI. Composition & arrangement: Giga. Performed in 定期公演『初』.', 1, '2026-05-27 13:20:33', '2026-05-27 13:20:33'),
(2, 'Luna say maybe', 'Luna say maybe', 'Temari Tsukimura', '00:04:25', '2024-05-16', 'Temari Tsukimura\'s debut solo song and signature track. Lyrics & composition: Minami (美波). Arrangement: Minami & Katsuhiro Mafune. Performed in the produce scenario \"Teiki Kouen Hatsu\" (定期公演『初』). ', 1, '2026-05-27 13:20:33', '2026-05-27 13:20:33'),
(3, 'Sekai Ichi Kawaii Watashi', '世界一可愛い私', 'Kotone Fujita', '00:03:59', '2024-05-16', 'Kotone Fujita\'s debut solo song. Lyrics, composition, and arrangement all by HoneyWorks — the duo behind the wildly popular \"Kokuhaku Jikkou Iinkai\" (Confession Executive Committee) series. ', 1, '2026-05-27 13:20:33', '2026-05-27 13:20:33');
