INSERT IGNORE INTO `producer_messages` (`id`, `producer_id`, `student_id`, `message_type`, `tone`, `message_text`) VALUES
(1, 1, 1, 'morning', 'firm', 'Morning, Saki. I know you already finished your 5km run. Save some energy for the lessons.'),
(2, 1, 1, 'morning', 'warm', 'Good morning. Up before sunrise again? Of course you were. Let\'s make today count.'),
(3, 1, 1, 'morning', 'playful', 'Morning, champ. Try not to lap the other students before first period this time.'),
(4, 1, 1, 'afternoon', 'warm', 'Halfway through the day and still going strong. Hydrate before dance practice.'),
(5, 1, 1, 'afternoon', 'firm', 'Afternoon. Don\'t let the energy drop now — finish the day as hard as you started it.'),
(6, 1, 1, 'afternoon', 'gentle', 'Quick check-in. You\'ve done plenty already today. Pace yourself through the rest.'),
(7, 1, 1, 'evening', 'gentle', 'Long day. You pushed hard — now actually let yourself wind down tonight.'),
(8, 1, 1, 'evening', 'warm', 'Good work today, Saki. Stretch, eat properly, and get real sleep. You earned it.'),
(9, 1, 1, 'evening', 'firm', 'It\'s evening. Training\'s over for the day. No \"one more set\" — go rest.'),
(10, 1, 1, 'low_vocal', 'serious', 'Your vocals slipped a little today. Breath control drills tomorrow — you\'ll close the gap fast.'),
(11, 1, 1, 'low_vocal', 'warm', 'Vocals weren\'t your best today, but you\'ve fixed bigger gaps than this. We\'ll work it.'),
(12, 1, 1, 'low_vocal', 'firm', 'The singing was off. Don\'t spiral over it — just channel that frustration into practice.'),
(13, 1, 1, 'low_dance', 'firm', 'Dance was below your usual standard. Unusual for you. Rest up, then we hit it again.'),
(14, 1, 1, 'low_dance', 'serious', 'Your footwork was tired today. That tells me you\'re overtraining. Ease off, then rebuild.'),
(15, 1, 1, 'low_dance', 'gentle', 'Even you have off days on the floor. One rough session doesn\'t erase all your work.'),
(16, 1, 1, 'low_visual', 'warm', 'Visual\'s your weaker area, and that\'s fine. We\'ll work the expressions until they\'re natural.'),
(17, 1, 1, 'low_visual', 'gentle', 'Posing felt stiff today. Relax your shoulders — you\'re competing, not bracing for impact.'),
(18, 1, 1, 'low_visual', 'serious', 'Visual scores need attention. Let\'s schedule extra camera time — you close gaps fast when focused.'),
(19, 1, 1, 'audition_day', 'firm', 'Audition day. You\'ve trained harder than anyone. Don\'t overthink — just show them what you\'ve got.'),
(20, 1, 1, 'audition_day', 'warm', 'Today\'s the stage. All those early runs and late practices? This is where they pay off.'),
(21, 1, 1, 'audition_day', 'serious', 'Audition day, Saki. Win or lose, leave nothing on the table. That\'s all I ask.'),
(22, 1, 1, 'rest_day', 'firm', 'It\'s a rest day. That means REST, Saki. Put the running shoes down. That\'s an order.'),
(23, 1, 1, 'rest_day', 'gentle', 'Take today off properly. Recovery is when the body actually gets stronger — trust me on this.'),
(24, 1, 1, 'rest_day', 'playful', 'Rest day. I\'ve hidden your running shoes. Don\'t bother looking — go relax instead.'),
(25, 1, 1, 'good_progress', 'warm', 'Your numbers are climbing every week. The discipline is paying off — I\'m proud of you.'),
(26, 1, 1, 'good_progress', 'firm', 'Solid progress. This is what consistency looks like. Keep the momentum, don\'t coast.'),
(27, 1, 1, 'good_progress', 'gentle', 'You\'re growing into your own idol, not anyone\'s rival. That\'s the best progress of all.'),
(28, 1, 2, 'morning', 'playful', 'Good morning. You actually woke up on time today — small miracles. Breakfast is the healthy one.'),
(29, 1, 2, 'morning', 'gentle', 'Morning, Temari. Take it slow if you need to, just don\'t fall back asleep on me.'),
(30, 1, 2, 'morning', 'warm', 'Up and ready? Good. The cool, composed Temari the fans love starts the moment you step out.'),
(31, 1, 2, 'afternoon', 'gentle', 'Afternoon check-in. Stay focused through the next lesson, then you can have your break.'),
(32, 1, 2, 'afternoon', 'playful', 'Halfway done. Yes, there\'s a snack break later. No, it\'s not cake. We discussed this.'),
(33, 1, 2, 'afternoon', 'warm', 'You\'re doing fine today. Push through the afternoon and the evening is yours.'),
(34, 1, 2, 'evening', 'warm', 'You did well today, even if you\'d never admit it out loud. Get some real sleep tonight.'),
(35, 1, 2, 'evening', 'gentle', 'Evening. The act can come off now — relax, you worked harder than you let on.'),
(36, 1, 2, 'evening', 'playful', 'Day\'s done. One small sweet won\'t hurt. ONE, Temari. I\'m watching.'),
(37, 1, 2, 'low_vocal', 'gentle', 'Vocals dipped a bit today — surprising, since it\'s your strength. Just an off day, nothing more.'),
(38, 1, 2, 'low_vocal', 'serious', 'Even your specialty needs upkeep. Don\'t coast on talent — a little practice keeps it sharp.'),
(39, 1, 2, 'low_vocal', 'warm', 'Not your sharpest singing today, but your baseline is still higher than most. Rest and reset.'),
(40, 1, 2, 'low_dance', 'serious', 'Dance needs more from you. I know the pace bores you, but the effort will show on stage.'),
(41, 1, 2, 'low_dance', 'firm', 'You held back in dance again. I can tell the difference between tired and uninterested.'),
(42, 1, 2, 'low_dance', 'playful', 'Your dance today had the energy of a nap. Let\'s find some actual enthusiasm tomorrow, hm?'),
(43, 1, 2, 'low_visual', 'playful', 'Visual scores are sleepy today, like someone I know. Let\'s wake those poses up tomorrow.'),
(44, 1, 2, 'low_visual', 'gentle', 'Your expressions read a little flat today. A bit more feeling and they\'ll land beautifully.'),
(45, 1, 2, 'low_visual', 'serious', 'Visual could use work. You have the look — now give the camera something behind the eyes.'),
(46, 1, 2, 'audition_day', 'firm', 'Audition day. Drop the cool act for the judges and actually let them see how good you are.'),
(47, 1, 2, 'audition_day', 'warm', 'Today\'s your stage. You\'ve done this before as the No.1 — that idol is still in there. Show them.'),
(48, 1, 2, 'audition_day', 'gentle', 'Audition day. No pressure act needed. Just be the performer I already know you are.'),
(49, 1, 2, 'rest_day', 'gentle', 'Rest day — your favorite. Enjoy it. You\'ve earned the downtime, sweets included. In moderation.'),
(50, 1, 2, 'rest_day', 'playful', 'Rest day. I know you\'ll spend it napping. At least nap somewhere comfortable this time.'),
(51, 1, 2, 'rest_day', 'warm', 'Take the day fully off. Recharge properly — you\'re better when you\'re actually rested.'),
(52, 1, 2, 'good_progress', 'warm', 'You\'re improving steadily, and the talent\'s finally meeting the effort. Keep this up.'),
(53, 1, 2, 'good_progress', 'playful', 'Look at you, working hard AND it\'s showing. Who is this person? I like her.'),
(54, 1, 2, 'good_progress', 'gentle', 'Real progress this week. See what happens when you let yourself try? Proud of you.'),
(55, 1, 3, 'morning', 'warm', 'Morning, Kotone. Big day ahead. Don\'t skip breakfast just to make an early shift.'),
(56, 1, 3, 'morning', 'playful', 'Good morning, hardest worker in the academy. Lessons first, money later. Deal?'),
(57, 1, 3, 'morning', 'gentle', 'Morning. You looked tired yesterday — please tell me you slept and didn\'t take a night shift.'),
(58, 1, 3, 'afternoon', 'playful', 'Afternoon already. Lesson first, then your shift — and yes, payday is on Friday.'),
(59, 1, 3, 'afternoon', 'warm', 'Doing great so far today. Eat something before you head off to work, alright?'),
(60, 1, 3, 'afternoon', 'firm', 'Afternoon. Finish the lesson properly before you start counting tonight\'s tips in your head.'),
(61, 1, 3, 'evening', 'gentle', 'You worked a full day AND a shift. That\'s enough. Go home and rest, please.'),
(62, 1, 3, 'evening', 'warm', 'Long day, hard worker. You did well. Now actually stop and take care of yourself tonight.'),
(63, 1, 3, 'evening', 'firm', 'It\'s evening. No picking up \"just one more\" shift. Rest is part of the investment too.'),
(64, 1, 3, 'low_vocal', 'warm', 'Vocals were a touch flat today. You\'re tired from overworking — a little rest fixes this.'),
(65, 1, 3, 'low_vocal', 'serious', 'Your singing slipped. I think the shifts are catching up to you. Something has to give.'),
(66, 1, 3, 'low_vocal', 'gentle', 'Not your best vocals today, but nothing sleep can\'t fix. Be kinder to yourself, okay?'),
(67, 1, 3, 'low_dance', 'serious', 'Dance is your strong stat, so today\'s dip tells me you\'re exhausted. Let\'s cut a shift this week.'),
(68, 1, 3, 'low_dance', 'firm', 'Your dance was off, and that\'s rare for you. The overwork is the problem. We\'re fixing your schedule.'),
(69, 1, 3, 'low_dance', 'warm', 'Even your best stat had an off day. You\'re running on empty — let me help lighten the load.'),
(70, 1, 3, 'low_visual', 'playful', 'Visual scores low? Impossible with that face. Just looked tired — get some sleep, superstar.'),
(71, 1, 3, 'low_visual', 'gentle', 'Your expressions were a bit dim today. That\'s exhaustion, not ability. Rest and you\'ll glow again.'),
(72, 1, 3, 'low_visual', 'serious', 'Visual dipped today. You rely on it for paid work, so let\'s protect it — that means resting.'),
(73, 1, 3, 'audition_day', 'firm', 'Audition day. This is the stage that actually pays off. Show them the confidence I know you have.'),
(74, 1, 3, 'audition_day', 'warm', 'Today\'s the big one. Forget the side jobs for a few hours — THIS is the real investment.'),
(75, 1, 3, 'audition_day', 'playful', 'Audition day. Go dazzle them. Think of the future endorsement money, if that helps motivate you.'),
(76, 1, 3, 'rest_day', 'firm', 'Rest day means no shifts. I checked the schedule — I know you tried to sneak one in. Rest.'),
(77, 1, 3, 'rest_day', 'gentle', 'Please take today off completely. No work. Your health is worth more than any paycheck.'),
(78, 1, 3, 'rest_day', 'warm', 'Day off, Kotone. Treat yourself to something nice with what you\'ve saved. You deserve it.'),
(79, 1, 3, 'good_progress', 'warm', 'Your progress is fantastic, and yes — there\'s a reward for it. You earned every bit of it.'),
(80, 1, 3, 'good_progress', 'playful', 'Numbers are up across the board. At this rate the sponsors will be fighting over you. Love it.'),
(81, 1, 3, 'good_progress', 'gentle', 'You\'re growing so much. Whatever goal that money is for, you\'re getting closer every week.'),
(82, 1, 4, 'morning', 'gentle', 'Good morning, Lilja. Take your time waking up — there\'s no rush. I\'m here when you\'re ready.'),
(83, 1, 4, 'morning', 'warm', 'Morning. You looked nervous yesterday, so today let\'s start small and easy together.'),
(84, 1, 4, 'morning', 'gentle', 'Hyvää huomenta, Lilja. Whichever language wakes you up gentler — both work for me.'),
(85, 1, 4, 'afternoon', 'warm', 'Afternoon check-in. You\'ve done well so far. Breathe — the hard part is already behind you.'),
(86, 1, 4, 'afternoon', 'gentle', 'How are you holding up? If anything\'s overwhelming you, please tell me. We can adjust.'),
(87, 1, 4, 'afternoon', 'warm', 'You\'re halfway through the day. Quietly proud of how you\'re handling everything.'),
(88, 1, 4, 'evening', 'gentle', 'Evening, Lilja. You worked hard today. Don\'t replay the small mistakes — just rest.'),
(89, 1, 4, 'evening', 'warm', 'Day\'s done, and you got through it. That itself is something to feel good about.'),
(90, 1, 4, 'evening', 'gentle', 'Sleep well tonight. Tomorrow\'s a new day, and you don\'t have to be perfect for it.'),
(91, 1, 4, 'low_vocal', 'gentle', 'Your voice was a little quiet today. Not bad — just shy. Let\'s find that volume together.'),
(92, 1, 4, 'low_vocal', 'warm', 'Vocals will come with confidence, and confidence comes with time. We\'re in no hurry.'),
(93, 1, 4, 'low_vocal', 'serious', 'Your singing has potential people don\'t see yet because you hold back. Let\'s work on letting go.'),
(94, 1, 4, 'low_dance', 'gentle', 'Dance felt uncertain today. That\'s okay — your movements get prettier when you stop overthinking.'),
(95, 1, 4, 'low_dance', 'warm', 'Tough dance session, hm? Don\'t apologize. We just keep practicing until it feels natural.'),
(96, 1, 4, 'low_dance', 'gentle', 'You hesitated a lot on the floor today. Trust your body — it knows more than you think.'),
(97, 1, 4, 'low_visual', 'warm', 'Visual was a little tense today. You\'re beautiful when you\'re relaxed — just breathe and smile.'),
(98, 1, 4, 'low_visual', 'gentle', 'The camera caught some stiffness today. It happens. We\'ll do a softer set tomorrow.'),
(99, 1, 4, 'low_visual', 'serious', 'You have everything a top idol needs visually. The only thing missing is believing it yourself.'),
(100, 1, 4, 'audition_day', 'gentle', 'Audition day. Nervous is normal. Whatever happens out there, I\'m proud of you for going.'),
(101, 1, 4, 'audition_day', 'warm', 'Today\'s the day. Remember — you don\'t have to be perfect. You just have to be yourself.'),
(102, 1, 4, 'audition_day', 'firm', 'Audition day. You\'ve trained for this. You belong on that stage as much as anyone — go show them.'),
(103, 1, 4, 'rest_day', 'gentle', 'Rest day. Take it slow, read, call home — whatever makes you feel calm. You\'ve earned it.'),
(104, 1, 4, 'rest_day', 'warm', 'Day off today. Please rest properly — no quietly practicing in your room thinking I won\'t notice.'),
(105, 1, 4, 'rest_day', 'gentle', 'A full rest day, Lilja. The world won\'t end if you take care of yourself for one day. Promise.'),
(106, 1, 4, 'good_progress', 'warm', 'Your progress this week was real, and visible. I hope you can see it the way I do.'),
(107, 1, 4, 'good_progress', 'gentle', 'You\'re growing, Lilja. Quietly, steadily — exactly the way that lasts. Very proud.'),
(108, 1, 4, 'good_progress', 'serious', 'The numbers don\'t lie. You\'re improving fast. Now it\'s time to believe what the results say.'),
(109, 1, 5, 'morning', 'warm', 'Morning, Sumika! You sound ready to take on the world already. Channel it into the lessons today.'),
(110, 1, 5, 'morning', 'playful', 'Good morning, captain. Pre-game pep talk: stretch, eat, smile — in that order. Let\'s go.'),
(111, 1, 5, 'morning', 'firm', 'Morning. I know you\'re fired up, but pace yourself — full day ahead, not a sprint.'),
(112, 1, 5, 'afternoon', 'warm', 'Afternoon, and you\'re still going strong. That sports background really shows in your stamina.'),
(113, 1, 5, 'afternoon', 'playful', 'Halftime, Sumika. Grab water, catch your breath, then we\'re back on the court.'),
(114, 1, 5, 'afternoon', 'firm', 'Good work this morning. Stay sharp — afternoon lessons are where your focus tends to slip.'),
(115, 1, 5, 'evening', 'gentle', 'Evening, Sumika. You went full speed all day. Now actually slow down — cooldown counts too.'),
(116, 1, 5, 'evening', 'warm', 'Long day, well played. Stretch properly tonight or your legs will hate you tomorrow.'),
(117, 1, 5, 'evening', 'firm', 'Day\'s over. No extra training tonight — recovery is part of the program, not a bonus.'),
(118, 1, 5, 'low_vocal', 'warm', 'Vocals dipped today — probably out of breath from putting your whole body into it. Let\'s pace it.'),
(119, 1, 5, 'low_vocal', 'serious', 'Singing isn\'t a sprint, Sumika. Less power, more control — your vocals will climb fast that way.'),
(120, 1, 5, 'low_vocal', 'gentle', 'A little off-key today, but the energy was there. We just need to tune the instrument now.'),
(121, 1, 5, 'low_dance', 'firm', 'Dance was below your level today. The athleticism is there — focus on hitting the counts cleanly.'),
(122, 1, 5, 'low_dance', 'serious', 'You moved fast but messy in dance. Precision over speed — that\'s the next step for you.'),
(123, 1, 5, 'low_dance', 'warm', 'Tougher dance session than usual. Don\'t take it to heart — your fundamentals are still solid.'),
(124, 1, 5, 'low_visual', 'gentle', 'Visual scores were lower today. Sometimes that big smile needs a moment of softness too. We\'ll practice.'),
(125, 1, 5, 'low_visual', 'serious', 'Visual needs work. You\'ve got the bright presence — now we add expression range to go with it.'),
(126, 1, 5, 'low_visual', 'playful', 'Your \"game face\" was a little too game today. Let\'s find some other expressions to add to the lineup.'),
(127, 1, 5, 'audition_day', 'firm', 'Audition day. Treat it like a final match — leave it all on the stage. You\'ve got this, Sumika.'),
(128, 1, 5, 'audition_day', 'warm', 'Today\'s your game day. All that training, all that sweat — go show them what you can do.'),
(129, 1, 5, 'audition_day', 'playful', 'Big match today. Pre-game ritual: deep breath, big smile, then knock \'em flat. Go!'),
(130, 1, 5, 'rest_day', 'firm', 'Rest day, Sumika. I know that\'s harder for you than training. Sit still. That\'s the assignment.'),
(131, 1, 5, 'rest_day', 'gentle', 'Day off today. Even athletes have recovery days — your body grows stronger when you actually rest.'),
(132, 1, 5, 'rest_day', 'warm', 'Full rest day. Do something fun, see friends, whatever\'s NOT a workout. You\'ve earned it.'),
(133, 1, 5, 'good_progress', 'warm', 'Your numbers are up, your energy is up — you\'re in great form right now. Keep this rhythm going.'),
(134, 1, 5, 'good_progress', 'firm', 'Strong week, Sumika. The effort is showing on the scoreboard. This is how champions train.'),
(135, 1, 5, 'good_progress', 'playful', 'Look at you climbing the rankings. The whole team is going to have to catch up to you at this rate.'),
(136, 1, 6, 'morning', 'gentle', 'Good morning, Hiro. I saw the library light on late again last night. Please eat before you read today.'),
(137, 1, 6, 'morning', 'warm', 'Morning. Your study habits are admirable, but your idol career needs you awake too. Coffee\'s on me.'),
(138, 1, 6, 'morning', 'playful', 'Good morning, scholar. Pop quiz: did you actually sleep last night? Show your work.'),
(139, 1, 6, 'afternoon', 'warm', 'Afternoon check-in. Your morning research went deep — don\'t lose track of time before the next lesson.'),
(140, 1, 6, 'afternoon', 'firm', 'It\'s afternoon. Stop replaying this morning\'s vocal session in your head. You did fine.'),
(141, 1, 6, 'afternoon', 'serious', 'Halfway through the day. Trust your prep — you over-prepare more than anyone else here.'),
(142, 1, 6, 'evening', 'gentle', 'Evening, Hiro. The library will still be there tomorrow. Please close the books tonight.'),
(143, 1, 6, 'evening', 'firm', 'It\'s evening. No more research today. Even geniuses need sleep — we\'ve had this conversation.'),
(144, 1, 6, 'evening', 'warm', 'Day\'s done. You worked hard, both physically and mentally. Take pride in that and rest.'),
(145, 1, 6, 'low_vocal', 'serious', 'Your vocals slipped today — I think you\'re analyzing each note instead of letting it flow. Less head, more heart.'),
(146, 1, 6, 'low_vocal', 'gentle', 'Vocals were a bit stiff today. You sing better when you stop trying to be perfect.'),
(147, 1, 6, 'low_vocal', 'warm', 'Today\'s singing was tense. The notes were right; the feeling needs to catch up. We\'ll work on it.'),
(148, 1, 6, 'low_dance', 'firm', 'Dance was below your level today. You\'re thinking through every count instead of moving with the music.'),
(149, 1, 6, 'low_dance', 'serious', 'Your dance was mechanical today. Technically clean — but cold. Let yourself feel the rhythm.'),
(150, 1, 6, 'low_dance', 'gentle', 'Dance felt overthought today. Trust your body — it doesn\'t need your brain micromanaging every step.'),
(151, 1, 6, 'low_visual', 'warm', 'Visual was a bit blank today. You have lovely features — let emotion through and the camera will love you.'),
(152, 1, 6, 'low_visual', 'serious', 'Your expressions today read as reading. Stop calculating the angle — just feel something on camera.'),
(153, 1, 6, 'low_visual', 'gentle', 'Visual scores low today. Try not to compose your face like an essay. A real smile will outperform any pose.'),
(154, 1, 6, 'audition_day', 'firm', 'Audition day, Hiro. You\'ve studied every angle of this. Now stop preparing and just perform.'),
(155, 1, 6, 'audition_day', 'warm', 'Today\'s the stage. You\'ve done the work three times over — trust it and let yourself shine.'),
(156, 1, 6, 'audition_day', 'serious', 'Audition day. The thinking is done. From here, your job is to feel, not analyze.'),
(157, 1, 6, 'rest_day', 'firm', 'Rest day. The library is closed to you today. I will check.'),
(158, 1, 6, 'rest_day', 'gentle', 'Day off, Hiro. Reading recreationally counts — but please, no textbooks today.'),
(159, 1, 6, 'rest_day', 'playful', 'Rest day. Defined as: learning nothing new. Yes, that includes the documentary you\'re queuing up.'),
(160, 1, 6, 'good_progress', 'warm', 'Your progress is excellent — and the part where you\'re trusting yourself more is the best part.'),
(161, 1, 6, 'good_progress', 'serious', 'Numbers are climbing across all areas. Discipline this consistent is rare. Well done.'),
(162, 1, 6, 'good_progress', 'gentle', 'You\'re growing past your habits — letting feeling into the performance. That\'s the harder kind of progress.'),
(163, 1, 7, 'morning', 'warm', 'Good morning, China. Council meeting first, then lessons. Eat properly between them, please.'),
(164, 1, 7, 'morning', 'gentle', 'Morning. Don\'t skip breakfast just because of an early council briefing — you\'ll feel it later.'),
(165, 1, 7, 'morning', 'playful', 'Good morning. Today\'s itinerary: be charming and brilliant. As usual. Easy day.'),
(166, 1, 7, 'afternoon', 'warm', 'Afternoon. You\'ve been juggling council duties and lessons beautifully today — keep that pace.'),
(167, 1, 7, 'afternoon', 'firm', 'Halfway through the day. Don\'t let council paperwork bleed into lesson focus. One thing at a time.'),
(168, 1, 7, 'afternoon', 'gentle', 'Afternoon check-in. If you\'re feeling stretched between council and idol work, please tell me.'),
(169, 1, 7, 'evening', 'warm', 'Evening, China. You did a lot today — for the council, for yourself, for everyone. Now rest.'),
(170, 1, 7, 'evening', 'gentle', 'Day\'s done. The thank-you notes can wait until morning. Please actually wind down tonight.'),
(171, 1, 7, 'evening', 'firm', 'It\'s evening. No more council emails tonight. Phone away, please.'),
(172, 1, 7, 'low_vocal', 'gentle', 'Vocals slipped a little today. You may be tired from council work — please don\'t spread yourself thin.'),
(173, 1, 7, 'low_vocal', 'warm', 'Today\'s singing was off your usual standard. We\'ll catch up tomorrow when you\'re less tired.'),
(174, 1, 7, 'low_vocal', 'serious', 'Your vocals dipped, and I don\'t think it\'s the singing — it\'s the schedule. We may need to talk.'),
(175, 1, 7, 'low_dance', 'gentle', 'Dance was a bit hesitant today. You have the grace — just commit to the movement.'),
(176, 1, 7, 'low_dance', 'warm', 'Dance felt held back today. You can let loose more than the polite version of you usually does.'),
(177, 1, 7, 'low_dance', 'serious', 'Dance needs more confidence from you. Manners off the stage, presence on it.'),
(178, 1, 7, 'low_visual', 'warm', 'Visual was lovely but too composed today. Let a real smile through, not the council-meeting one.'),
(179, 1, 7, 'low_visual', 'gentle', 'Visual scores dipped a touch. Try a more relaxed expression — you\'re not on duty in front of the camera.'),
(180, 1, 7, 'low_visual', 'playful', 'Your visual today was very \"Ms. Class Representative.\" Let\'s see Idol China next time, hm?'),
(181, 1, 7, 'audition_day', 'firm', 'Audition day, China. The poise you bring to council? Bring it to the stage. You\'ve got this.'),
(182, 1, 7, 'audition_day', 'warm', 'Today\'s the day. Turn those public-speaking duties into stage presence — they won\'t look away.'),
(183, 1, 7, 'audition_day', 'gentle', 'Audition day. Whatever happens, your manners and your effort will leave a good impression. Be yourself.'),
(184, 1, 7, 'rest_day', 'firm', 'Rest day. No council emails, no event prep, no piano scales. Yes, I checked — actually rest.'),
(185, 1, 7, 'rest_day', 'gentle', 'Day off today, China. Let yourself just be a teenager for one day. The world won\'t fall apart.'),
(186, 1, 7, 'rest_day', 'warm', 'Rest day. Family time is fine, but no council work please. Recharge properly.'),
(187, 1, 7, 'good_progress', 'warm', 'Your progress is real — and somehow you\'re doing it while running the council. Genuinely impressive.'),
(188, 1, 7, 'good_progress', 'gentle', 'You\'ve grown so much this week, in lessons and as a leader. Very proud of you.'),
(189, 1, 7, 'good_progress', 'firm', 'Numbers are up across the board. This is what disciplined balance looks like. Keep going.'),
(190, 1, 8, 'morning', 'playful', 'Morning, Ume. Yes, Saki was already out running before you. No, it\'s not a race — but I know that won\'t stop you.'),
(191, 1, 8, 'morning', 'warm', 'Good morning. Channel that competitive fire into lessons today, not just the running.'),
(192, 1, 8, 'morning', 'firm', 'Morning. Run, eat, then lessons — in that order. You don\'t have to outpace Saki today.'),
(193, 1, 8, 'afternoon', 'playful', 'Afternoon check-in. You\'re glowing — already beat your morning run time? Of course you did.'),
(194, 1, 8, 'afternoon', 'warm', 'Halfway through. You\'ve kept your energy up all day, which is exactly what idols need.'),
(195, 1, 8, 'afternoon', 'firm', 'Afternoon. Stay focused through the next lesson — competing isn\'t always about the obvious thing.'),
(196, 1, 8, 'evening', 'gentle', 'Evening, Ume. You worked twice as hard as anyone today. Now actually let yourself wind down.'),
(197, 1, 8, 'evening', 'warm', 'Day\'s done. Your sister would be proud — even if she\'d never say it. I\'ll say it for her.'),
(198, 1, 8, 'evening', 'playful', 'Evening. The day is over. Saki is NOT secretly doing extra training in her room right now. Probably. Go rest.'),
(199, 1, 8, 'low_vocal', 'warm', 'Vocals were a bit off today. Less power, more feeling — it\'s not a contest to hit notes the hardest.'),
(200, 1, 8, 'low_vocal', 'gentle', 'Singing slipped today. Don\'t let one rough session shake you — you bounce back fast.'),
(201, 1, 8, 'low_vocal', 'firm', 'Vocals weren\'t your best, Ume. You don\'t have to match Saki on every stat — improve your own pace.'),
(202, 1, 8, 'low_dance', 'firm', 'Dance was below your level today. Stop trying to dance bigger than her and dance like YOU.'),
(203, 1, 8, 'low_dance', 'serious', 'Today\'s dance felt rushed. You have stamina for days — you don\'t need to prove it in the first lesson.'),
(204, 1, 8, 'low_dance', 'gentle', 'Dance was tired today. Tiring yourself out doesn\'t impress anyone — not even Saki, and that\'s saying something.'),
(205, 1, 8, 'low_visual', 'gentle', 'Visual scores dipped today. Your cute smile is your weapon — use it instead of borrowing Saki\'s intense look.'),
(206, 1, 8, 'low_visual', 'warm', 'Visual was off today. You light up best when you\'re being playful Ume, not serious Saki-clone.'),
(207, 1, 8, 'low_visual', 'playful', 'Visual scores low? That serious face was 100% your sister\'s. Bring back your own grin tomorrow.'),
(208, 1, 8, 'audition_day', 'firm', 'Audition day, Ume. This isn\'t about beating Saki. Show the judges who YOU are.'),
(209, 1, 8, 'audition_day', 'warm', 'Today\'s the stage. All those runs, all that practice — go give them the bright Ume only YOU can be.'),
(210, 1, 8, 'audition_day', 'playful', 'Big day, little Hanami. Beat your own record, not anyone else\'s. Now go shine.'),
(211, 1, 8, 'rest_day', 'firm', 'Rest day. I know Saki tries to sneak training in too — don\'t follow her example today. Actually rest.'),
(212, 1, 8, 'rest_day', 'gentle', 'Day off. Whatever Saki\'s doing, you don\'t have to copy it. Be a person, not a competition.'),
(213, 1, 8, 'rest_day', 'playful', 'Rest day. Mandatory relaxing, no sister-sparring allowed. Saki has the same orders.'),
(214, 1, 8, 'good_progress', 'warm', 'Your progress this week is wonderful. And it\'s all YOU — not because of anyone else. Proud of you.'),
(215, 1, 8, 'good_progress', 'firm', 'Solid week, Ume. Numbers are up and you did it your way — not by copying. Keep that.'),
(216, 1, 8, 'good_progress', 'playful', 'Look at you climbing the rankings. Saki may actually start worrying — I won\'t tell her you\'re catching up.'),
(217, 1, 9, 'morning', 'playful', 'Good morning. I know — five more minutes. You\'ve used those five minutes seven times already.'),
(218, 1, 9, 'morning', 'gentle', 'Morning, Misuzu. Up, please. Council meeting in 20 minutes. Yes, you have to be awake for that one.'),
(219, 1, 9, 'morning', 'firm', 'Morning. I\'m not coming back in ten minutes. Get up. Lessons don\'t pause for nap protests.'),
(220, 1, 9, 'afternoon', 'playful', 'Afternoon check-in. You\'re surprisingly awake today — what happened? Did the nap actually work?'),
(221, 1, 9, 'afternoon', 'warm', 'Halfway through the day. You did well this morning — try to stay conscious through the next lesson.'),
(222, 1, 9, 'afternoon', 'gentle', 'Afternoon, Misuzu. A quick break before the next session is fine. A four-hour break is not.'),
(223, 1, 9, 'evening', 'playful', 'Evening. The day is over. Yes, you can sleep now. I know it\'s been on your mind since 9 AM.'),
(224, 1, 9, 'evening', 'warm', 'Day\'s done. You stayed awake for most of it today — that\'s real progress. Sleep properly tonight.'),
(225, 1, 9, 'evening', 'gentle', 'Evening, Misuzu. Don\'t nap so late it ruins your night sleep. We\'ve been here before.'),
(226, 1, 9, 'low_vocal', 'gentle', 'Vocals were sleepy today. When you actually wake up, you sing beautifully — let\'s find that more often.'),
(227, 1, 9, 'low_vocal', 'playful', 'Singing while half-asleep is a niche skill, but the judges prefer fully awake idols. Just a tip.'),
(228, 1, 9, 'low_vocal', 'serious', 'Your vocals dropped today because you weren\'t really there. Talent is wasted on naps, Misuzu.'),
(229, 1, 9, 'low_dance', 'firm', 'Dance was slow today. And not stylish-slow — sleepy-slow. We need actual movement, please.'),
(230, 1, 9, 'low_dance', 'playful', 'Your dance today had the energy of a yawn. Charming, but not what we\'re going for.'),
(231, 1, 9, 'low_dance', 'gentle', 'Dance scores dipped. You move beautifully when awake — let\'s get you there BEFORE lessons next time.'),
(232, 1, 9, 'low_visual', 'playful', 'Visual scores low? Half-closed eyes are a vibe, but apparently not THE vibe. Try open ones tomorrow.'),
(233, 1, 9, 'low_visual', 'gentle', 'Visual was tired today. A nap BEFORE the lesson, not during — that\'s the rule.'),
(234, 1, 9, 'low_visual', 'warm', 'Your expressions were soft today, almost dreamy. Pretty in the right context, but we need range.'),
(235, 1, 9, 'audition_day', 'firm', 'Audition day, Misuzu. No napping. I MEAN IT. We\'ve prepared too much for you to sleep through your slot.'),
(236, 1, 9, 'audition_day', 'warm', 'Today\'s the stage. You\'re more talented than you let on — show them the version of you that wakes up for it.'),
(237, 1, 9, 'audition_day', 'playful', 'Audition day. Coffee? Tea? Light shake? Whatever wakes you up — pick one and let\'s go.'),
(238, 1, 9, 'rest_day', 'warm', 'Rest day. Your favorite. Enjoy it — this is the one day I won\'t complain about the napping.'),
(239, 1, 9, 'rest_day', 'playful', 'Rest day, Misuzu. Today, the napping is officially endorsed. Don\'t get used to it.'),
(240, 1, 9, 'rest_day', 'gentle', 'Day off. You\'ve earned the sleep this week. Recharge properly so we can have you AWAKE tomorrow.'),
(241, 1, 9, 'good_progress', 'warm', 'Your numbers are up — and you didn\'t miss many lessons this week. That\'s huge for you.'),
(242, 1, 9, 'good_progress', 'playful', 'Look who stayed awake long enough to actually improve. I see you, Misuzu. Genuinely proud.'),
(243, 1, 9, 'good_progress', 'gentle', 'You\'re growing steadily, even with all the naps. Imagine what you\'d do if you slept normally at night.'),
(244, 1, 1, 'birthday', 'firm', 'Happy birthday, Saki. Today is the ONE day I\'m ordering you to rest — and yes, I\'ll enforce it.'),
(245, 1, 1, 'birthday', 'warm', 'Happy birthday. Another year of being the most driven person in this academy. Proud of how far you\'ve pushed yourself.'),
(246, 1, 1, 'birthday', 'playful', 'Happy birthday! Let me guess — you still went for the morning run today. Of course you did. The REST of the day, please rest.'),
(247, 1, 2, 'birthday', 'playful', 'Happy birthday, Temari. Today only — yes, you can have the cake. The whole slice. I\'ll allow it.'),
(248, 1, 2, 'birthday', 'warm', 'Happy birthday. Another year, and you\'re still the most effortlessly cool person in this academy. Enjoy your day.'),
(249, 1, 2, 'birthday', 'gentle', 'Happy birthday, Temari. Take the day completely off — no diet management, no schedule. Today is yours, sweets included.'),
(250, 1, 3, 'birthday', 'warm', 'Happy birthday, Kotone. Today there is no shift, no overtime, no bargaining. Your present is mandatory time off.'),
(251, 1, 3, 'birthday', 'playful', 'Happy birthday! And yes, there\'s a bonus envelope in it for you. Don\'t say I never gave you anything.'),
(252, 1, 3, 'birthday', 'firm', 'Happy birthday. I checked — I know you tried to schedule a shift today. Cancel it. We\'re celebrating you, not your hustle.'),
(253, 1, 4, 'birthday', 'gentle', 'Happy birthday, Lilja. Hyvää syntymäpäivää. May this year bring you the confidence I already see in you.'),
(254, 1, 4, 'birthday', 'warm', 'Happy birthday. You\'ve grown so much this year — quietly, beautifully. Today, please let everyone celebrate you.'),
(255, 1, 4, 'birthday', 'gentle', 'Happy birthday, Lilja. No pressure today, no lessons — just whatever makes you feel calm and happy. You deserve it.'),
(256, 1, 5, 'birthday', 'playful', 'Happy birthday, Sumika! Today\'s match has only one rule: NO TRAINING. Yes, that\'s the hard part for you.'),
(257, 1, 5, 'birthday', 'warm', 'Happy birthday. The energy you bring to every day is contagious — today, let everyone bring it back to you.'),
(258, 1, 5, 'birthday', 'firm', 'Happy birthday. I see you eyeing the tennis court. The court is closed for you today, captain. REST.'),
(259, 1, 6, 'birthday', 'playful', 'Happy birthday, Hiro. The library is officially closed to you today. I have the keys. Don\'t try me.'),
(260, 1, 6, 'birthday', 'warm', 'Happy birthday. Another year of being the brightest mind in the academy. Today, you\'re allowed to feel before you think.'),
(261, 1, 6, 'birthday', 'firm', 'Happy birthday, Hiro. No research, no studying, no productive learning today. That IS the celebration.'),
(262, 1, 7, 'birthday', 'warm', 'Happy birthday, China. Today, no council duties, no event planning. You get to be CELEBRATED, not the celebrator.'),
(263, 1, 7, 'birthday', 'gentle', 'Happy birthday, China. Enjoy your family\'s celebrations today — and remember, we\'re celebrating you here too.'),
(264, 1, 7, 'birthday', 'playful', 'Happy birthday! I\'ve informed the Student Council that their finest member gets the day off. They\'ll manage without you.'),
(265, 1, 8, 'birthday', 'playful', 'Happy birthday, Ume! And yes, your birthday is entirely YOURS today — Saki doesn\'t get to compete on this one.'),
(266, 1, 8, 'birthday', 'warm', 'Happy birthday. Another year of being your own bright, energetic self — not anyone\'s shadow. Today, especially, shine.'),
(267, 1, 8, 'birthday', 'gentle', 'Happy birthday, Ume. The morning run can wait. The training can wait. Today, just be celebrated. You earned it.'),
(268, 1, 9, 'birthday', 'playful', 'Happy birthday, Misuzu! Today\'s gift: official permission to nap as much as you want. Use it wisely.'),
(269, 1, 9, 'birthday', 'warm', 'Happy birthday. Another year, and somehow you keep proving you\'re more capable than the napping suggests. Proud of you.'),
(270, 1, 9, 'birthday', 'gentle', 'Happy birthday, Misuzu. We\'ll wake you up for cake. Otherwise, the bed is yours all day.'),
(298, 1, 10, 'birthday', 'warm', 'Happy birthday, Mao. The dormitory\'s \"Little Prince\" deserves a day where someone takes care of HER for once. Let us.'),
(299, 1, 10, 'birthday', 'playful', 'Happy birthday! I booked you a hot spring trip for the weekend — figured the dorm\'s favorite capybara would appreciate it.'),
(300, 1, 10, 'birthday', 'firm', 'Happy birthday, Mao. Today you\'re not the dorm supervisor and not the older sister figure. You\'re just Mao. Enjoy it.'),
(301, 1, 11, 'birthday', 'warm', 'Happy birthday, Rinami. The \"onee-sama\" of the dorm gets to be spoiled today, not the one doing the spoiling. Sushi\'s on me.'),
(302, 1, 11, 'birthday', 'playful', 'Happy birthday! I made reservations at the sushi place you\'ve been eyeing for months. Yes, all-you-can-eat. Don\'t hold back.'),
(303, 1, 11, 'birthday', 'gentle', 'Happy birthday, Rinami. Today, please let everyone return all the kindness you constantly give us. You deserve every bit of it.'),
(304, 1, 12, 'birthday', 'warm', 'Happy birthday, Sena. Today the Prima Stella is just a girl turning a year older — and that\'s a wonderful thing. Enjoy your day.'),
(305, 1, 12, 'birthday', 'gentle', 'Happy birthday. Even the Academy\'s Top Idol gets a day off from being perfect. Relax, eat cake, be ordinary for a few hours.'),
(306, 1, 12, 'birthday', 'playful', 'Happy birthday, Sena. I\'ve forbidden you from approaching Kotone today — let her enjoy your birthday in peace. We can try again tomorrow.'),
(307, 1, 13, 'birthday', 'warm', 'Happy birthday, Tsubame. Even No.2 deserves to be the center of attention for one day. Today\'s yours, not Sena\'s.'),
(308, 1, 13, 'birthday', 'playful', 'Happy birthday! I got you the latest mecha figure you\'ve been pretending you don\'t want. Don\'t try to play it cool — I see you.'),
(309, 1, 13, 'birthday', 'firm', 'Happy birthday, Tsubame. Today, the rivalry with Sena is on pause. Even future Prima Stellas need to rest before the next campaign.'),
(310, 1, 10, 'morning', 'warm', 'Good morning, Mao. I know you were up early checking on the dorms. Eat your own breakfast before you start mothering everyone.'),
(311, 1, 10, 'morning', 'gentle', 'Morning. The \"little prince\" has a full day ahead — but please take a moment for yourself first.'),
(312, 1, 10, 'morning', 'firm', 'Morning, Mao. The first-years can fend for themselves at breakfast. Take care of YOU first today.'),
(313, 1, 10, 'afternoon', 'warm', 'Afternoon check-in. You\'ve been running between lessons and dorm duties all morning — water break, please.'),
(314, 1, 10, 'afternoon', 'firm', 'Halfway through. Don\'t let dorm supervisor duties bleed into your own practice time.'),
(315, 1, 10, 'afternoon', 'gentle', 'Afternoon, Mao. If you\'re tired, it\'s okay to admit it. The younger ones won\'t think less of you.'),
(316, 1, 10, 'evening', 'warm', 'Evening. The dorm\'s \"little prince\" earned her crown today. Now please, rest.'),
(317, 1, 10, 'evening', 'gentle', 'Day\'s done. Stop checking on everyone else and check on yourself for once.'),
(318, 1, 10, 'evening', 'firm', 'It\'s evening, Mao. No more \"just one more thing\" for the dorm. Your room is your room — actually use it.'),
(319, 1, 10, 'low_vocal', 'gentle', 'Vocals slipped a little today. You may be wearing yourself thin between practice and dorm duties. Let\'s recalibrate.'),
(320, 1, 10, 'low_vocal', 'warm', 'Today\'s singing wasn\'t your best. You\'ve been giving so much to others — give some of that energy back to yourself.'),
(321, 1, 10, 'low_vocal', 'serious', 'Your vocals dipped today. As a senior, you set the example — but the example shouldn\'t be \"work yourself dry.\"'),
(322, 1, 10, 'low_dance', 'firm', 'Dance was below your level today. Your cool style needs energy behind it, and you\'re running low.'),
(323, 1, 10, 'low_dance', 'warm', 'Dance wasn\'t sharp today. The \"cool\" image only works when you\'re not exhausted. Rest more.'),
(324, 1, 10, 'low_dance', 'serious', 'Your dance was tired. You\'ve earned the cool reputation — don\'t let upkeep on the dorm cost you it.'),
(325, 1, 10, 'low_visual', 'gentle', 'Visual scores dipped today. Your \"prince\" presence needs you to actually be present — not running dorm checklists in your head.'),
(326, 1, 10, 'low_visual', 'warm', 'Visual was a bit soft today. When you\'re fully there, that cool charm is unbeatable. Let\'s get you back to it.'),
(327, 1, 10, 'low_visual', 'firm', 'Visual was off. Stop mentally running dorm duties during your photoshoots — I can tell when you\'re doing it.'),
(328, 1, 10, 'audition_day', 'firm', 'Audition day, Mao. The dorm is fine without you for a few hours. Be the cool idol you\'ve been working toward.'),
(329, 1, 10, 'audition_day', 'warm', 'Today\'s the stage. All those years of pursuing the cool idol you wanted to be — show them THAT Mao.'),
(330, 1, 10, 'audition_day', 'serious', 'Audition day. You\'ve been waiting a long time to be seen as cool, not assigned-cute. This is the moment.'),
(331, 1, 10, 'rest_day', 'firm', 'Rest day. The dorm runs without you for one day. I\'ve told the first-years not to bother you. Actually rest.'),
(332, 1, 10, 'rest_day', 'warm', 'Day off today. Go to the hot springs, soak like the capybara you secretly are. You\'ve earned it.'),
(333, 1, 10, 'rest_day', 'gentle', 'Rest day, Mao. Stop checking on the younger ones. Today, someone else takes care of them. Let them.'),
(334, 1, 10, 'good_progress', 'warm', 'Your progress is excellent — and you\'re doing it while running the entire dorm. Quietly amazed by you.'),
(335, 1, 10, 'good_progress', 'serious', 'Numbers up across the board. The cool idol image is coming together. Years of work are paying off.'),
(336, 1, 10, 'good_progress', 'gentle', 'You\'re growing into exactly the idol you wanted to be — the cool one, not the assigned-cute one. Very proud.'),
(337, 1, 11, 'morning', 'warm', 'Good morning, Rinami. I know you already woke the first-years for breakfast. Now please eat yours.'),
(338, 1, 11, 'morning', 'playful', 'Morning, onee-sama. The dorm runs because of you — but please don\'t forget breakfast for yourself again.'),
(339, 1, 11, 'morning', 'gentle', 'Good morning. Today\'s first thought: take care of YOURSELF before everyone else. Promise me.'),
(340, 1, 11, 'afternoon', 'warm', 'Afternoon. You\'ve been looking after everyone all morning. Take a break with actual food, not bites stolen between things.'),
(341, 1, 11, 'afternoon', 'playful', 'Halfway through the day. I know you packed enough lunch for three people. Eat all of it. Don\'t share.'),
(342, 1, 11, 'afternoon', 'gentle', 'Afternoon check-in. If you\'re feeling stretched between caring for others and your own work, please tell me.'),
(343, 1, 11, 'evening', 'warm', 'Evening, Rinami. The \"onee-sama\" of the dorm worked hard today. Now let yourself wind down.'),
(344, 1, 11, 'evening', 'gentle', 'Day\'s done. Stop tidying up after everyone tonight. The dorm survives one messy evening, I promise.'),
(345, 1, 11, 'evening', 'playful', 'Evening. Yes, the sushi place is open. Yes, you can go. You\'ve earned it ten times over.'),
(346, 1, 11, 'low_vocal', 'gentle', 'Vocals dipped today. You may be tired from looking after everyone — please put yourself first sometimes.'),
(347, 1, 11, 'low_vocal', 'warm', 'Today\'s singing wasn\'t your best. Even the most reliable onee-sama needs rest. We\'ll catch up tomorrow.'),
(348, 1, 11, 'low_vocal', 'serious', 'Your vocals slipped today. You give so much energy to others — there\'s none left for your own performance.'),
(349, 1, 11, 'low_dance', 'warm', 'Dance felt heavy today. You might be carrying everyone else\'s load. Let it go for a few hours.'),
(350, 1, 11, 'low_dance', 'gentle', 'Today\'s dance was a bit off. Your stamina is amazing, but not infinite — even you need rest.'),
(351, 1, 11, 'low_dance', 'firm', 'Dance below your level today. Stop solving dorm drama during practice — focus is yours, not theirs.'),
(352, 1, 11, 'low_visual', 'gentle', 'Visual was a bit dull today. Your warmth is your best feature on camera — let it through, don\'t mute it.'),
(353, 1, 11, 'low_visual', 'warm', 'Today\'s visual scores dipped. You light up rooms naturally — bring that to the lens, not just to the dorm.'),
(354, 1, 11, 'low_visual', 'playful', 'Visual was sleepy today. Onee-sama tired? Even you deserve a nap. Try one before tomorrow\'s session.'),
(355, 1, 11, 'audition_day', 'firm', 'Audition day, Rinami. Today is YOUR stage, not anyone else\'s. Be the idol, not the caretaker.'),
(356, 1, 11, 'audition_day', 'warm', 'Today\'s the day. Show the judges the same warmth and care you give everyone — but make it about YOU this time.'),
(357, 1, 11, 'audition_day', 'gentle', 'Audition day. Whatever happens, your kindness shines through everything you do. Trust it on stage.'),
(358, 1, 11, 'rest_day', 'firm', 'Rest day. You don\'t cook for anyone today. You don\'t tidy up after anyone today. You rest. Period.'),
(359, 1, 11, 'rest_day', 'warm', 'Day off, Rinami. Go eat sushi, take a long bath, do nothing productive. The dorm runs itself for one day.'),
(360, 1, 11, 'rest_day', 'gentle', 'Rest day. Even the kindest onee-sama deserves to be looked after. Today, please let yourself just BE.'),
(361, 1, 11, 'good_progress', 'warm', 'Your progress is wonderful — and you\'re doing it while basically raising half the dorm. You\'re extraordinary.'),
(362, 1, 11, 'good_progress', 'gentle', 'Real growth this week, Rinami. The talent shines through when you let yourself focus. Very proud.'),
(363, 1, 11, 'good_progress', 'playful', 'Numbers are up, and you\'re still doing it all with that warm smile. You\'re showing off, onee-sama. Keep it up.'),
(364, 1, 12, 'morning', 'warm', 'Good morning, Sena. Today the Prima Stella starts with breakfast — the ordinary kind. No elite training schedule before lessons.'),
(365, 1, 12, 'morning', 'serious', 'Morning. Stage presence starts now, not at the lesson. Carry that posture through the whole day.'),
(366, 1, 12, 'morning', 'playful', 'Good morning, Prima Stella. Yes, I saw your phone wallpaper of Kotone. We\'re talking about that later.'),
(367, 1, 12, 'afternoon', 'warm', 'Afternoon check-in. You handled the morning beautifully — keep that grace into the afternoon.'),
(368, 1, 12, 'afternoon', 'firm', 'Halfway through. The throne doesn\'t carry itself — stay focused through the next lesson.'),
(369, 1, 12, 'afternoon', 'gentle', 'Afternoon, Sena. If anything off-stage is on your mind, set it aside until practice ends. We can talk after.'),
(370, 1, 12, 'evening', 'warm', 'Evening, Sena. The Prima Stella worked hard today. Now please let her rest like a normal person.'),
(371, 1, 12, 'evening', 'gentle', 'Day\'s done. The crown comes off in the evening — be Sena tonight, not the title.'),
(372, 1, 12, 'evening', 'firm', 'It\'s evening. No more \"should I message Kotone\" overthinking tonight. Phone away. Sleep.'),
(373, 1, 12, 'low_vocal', 'serious', 'Your vocals dipped today. I know you feel like you\'ve peaked — but the ceiling moves when you push. Push.'),
(374, 1, 12, 'low_vocal', 'gentle', 'Vocals weren\'t your best today. Even Prima Stella has off days. It doesn\'t dethrone you — it just makes you human.'),
(375, 1, 12, 'low_vocal', 'warm', 'Today\'s singing slipped a touch. Don\'t read it as plateau panic. Read it as a signal to try something new tomorrow.'),
(376, 1, 12, 'low_dance', 'firm', 'Dance was below your level today. You\'re moving like someone defending a title, not climbing past it. Climb.'),
(377, 1, 12, 'low_dance', 'serious', 'Dance felt static today. The Prima Stella who plays it safe gets caught from behind. Push your range.'),
(378, 1, 12, 'low_dance', 'warm', 'Dance wasn\'t sharp today. You\'ve been at the top so long the muscles forget what climbing feels like. Let\'s rebuild that.'),
(379, 1, 12, 'low_visual', 'gentle', 'Visual scores dipped today. The polished idol routine is showing its seams — let some real Sena through.'),
(380, 1, 12, 'low_visual', 'warm', 'Today\'s visual was very controlled. Too controlled. Loosen up — perfection is less interesting than presence.'),
(381, 1, 12, 'low_visual', 'firm', 'Visual was off today. Stop performing the Prima Stella role and just BE her. There\'s a difference, and you know it.'),
(382, 1, 12, 'audition_day', 'firm', 'Audition day, Sena. You\'re the Prima Stella — but today, treat yourself like a challenger again. That\'s where growth lives.'),
(383, 1, 12, 'audition_day', 'warm', 'Today\'s the stage. The throne is yours to defend, but lead with curiosity, not duty. Show them something new.'),
(384, 1, 12, 'audition_day', 'serious', 'Audition day. Years of elite training, the title, the legacy — none of it matters if you don\'t show up hungry today.'),
(385, 1, 12, 'rest_day', 'gentle', 'Rest day, Sena. No scouting Kotone today. No council follow-ups. Be a teenage girl for a day.'),
(386, 1, 12, 'rest_day', 'firm', 'Rest day. The crown stays in the drawer. Yes, I\'ll check that you didn\'t try to schedule extra practice.'),
(387, 1, 12, 'rest_day', 'playful', 'Rest day. I\'ve put a \"do not approach\" sign on Kotone for your protection AND hers. You\'re welcome.'),
(388, 1, 12, 'good_progress', 'warm', 'Your progress is real this week — and you actually let yourself try new things. That\'s the harder kind of growth.'),
(389, 1, 12, 'good_progress', 'serious', 'Numbers up across the board. You broke the plateau by treating yourself like a student again. Keep that mindset.'),
(390, 1, 12, 'good_progress', 'gentle', 'You\'ve grown this week, Sena — not just as an idol but as a person. Both matter. Proud of you.'),
(391, 1, 13, 'morning', 'firm', 'Morning, Tsubame. Today\'s training starts now. No coasting on yesterday\'s results — Sena isn\'t coasting either.'),
(392, 1, 13, 'morning', 'warm', 'Good morning. The No.2 idol is ready to climb. Today, focus on YOUR improvement, not Sena\'s distance.'),
(393, 1, 13, 'morning', 'playful', 'Morning, vice president. I won\'t tell anyone about the new mecha figure on your shelf if you stretch first.'),
(394, 1, 13, 'afternoon', 'firm', 'Afternoon. The morning was solid — don\'t ease off now. Climbers don\'t get to rest mid-mountain.'),
(395, 1, 13, 'afternoon', 'serious', 'Halfway through. Sena\'s stats today are exactly the number you should be targeting. Aim higher.'),
(396, 1, 13, 'afternoon', 'warm', 'Afternoon check-in. You\'re holding pace well today. The path past her starts with days like this.'),
(397, 1, 13, 'evening', 'gentle', 'Evening, Tsubame. The crown isn\'t given by training alone — but you\'ve earned tonight\'s rest. Take it.'),
(398, 1, 13, 'evening', 'firm', 'It\'s evening. Stop replaying every count from today\'s dance. The work is done — recovery is part of training.');
INSERT IGNORE INTO `producer_messages` (`id`, `producer_id`, `student_id`, `message_type`, `tone`, `message_text`) VALUES
(399, 1, 13, 'evening', 'warm', 'Day\'s done. You moved closer to her today, even if you can\'t measure it. Sleep on that and start fresh tomorrow.'),
(400, 1, 13, 'low_vocal', 'firm', 'Vocals were below your level today. The path to Prima Stella doesn\'t allow these slip-ups. Sharpen up.'),
(401, 1, 13, 'low_vocal', 'serious', 'Today\'s singing slipped. Misuzu beat you once because complacency snuck in — don\'t let it back.'),
(402, 1, 13, 'low_vocal', 'warm', 'Vocals weren\'t your best today. Even the most disciplined idol has rough days. Tomorrow we reset.'),
(403, 1, 13, 'low_dance', 'firm', 'Dance was below your level today. Pride doesn\'t compensate for sloppy footwork. Tomorrow you fix it.'),
(404, 1, 13, 'low_dance', 'serious', 'Today\'s dance was tense. You\'re trying to outdo Sena instead of perform — those are different things.'),
(405, 1, 13, 'low_dance', 'gentle', 'Dance wasn\'t sharp today. You don\'t have to fight every count — sometimes the movement comes when you stop forcing it.'),
(406, 1, 13, 'low_visual', 'firm', 'Visual was off today. The pompous attitude works on stage; the camera needs more than just attitude.'),
(407, 1, 13, 'low_visual', 'serious', 'Visual scores dipped today. You compose your face like you\'re entering a council meeting. Loosen up.'),
(408, 1, 13, 'low_visual', 'playful', 'Visual today was very \"future Prima Stella declaring war.\" Try \"person who actually enjoys being on camera\" next time.'),
(409, 1, 13, 'audition_day', 'firm', 'Audition day, Tsubame. Forget the rivalry for three hours. Show them YOUR idol, not Sena\'s shadow\'s idol.'),
(410, 1, 13, 'audition_day', 'warm', 'Today\'s the stage. All those years of climbing toward the top — show the judges you belong there now.'),
(411, 1, 13, 'audition_day', 'serious', 'Audition day. This is where the gap closes. Not in talk, not in training — here, in front of them.'),
(412, 1, 13, 'rest_day', 'firm', 'Rest day. No extra training. Yes, I checked your schedule. Yes, I\'ll be checking again.'),
(413, 1, 13, 'rest_day', 'gentle', 'Day off, Tsubame. Even rivals rest. Sena is resting too — you don\'t lose ground by sleeping.'),
(414, 1, 13, 'rest_day', 'playful', 'Rest day. Permission granted to watch mecha all day. I\'ll pretend not to know about the figure collection.'),
(415, 1, 13, 'good_progress', 'warm', 'Your progress this week was real. The gap to Sena is smaller — and not because she dropped, because you climbed.'),
(416, 1, 13, 'good_progress', 'firm', 'Numbers up across the board. This is what disciplined climbing looks like. Hold this pace.'),
(417, 1, 13, 'good_progress', 'serious', 'You broke through something this week. The complacency is gone. The Prima Stella seat is in reach if you keep this up.');
