-- Fixed import file for gakumas_sms sample data
-- This version imports parent tables before child tables and disables FK checks during refresh.
-- WARNING: It clears the listed sample-data tables before inserting these rows.

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET time_zone = "+00:00";
SET NAMES utf8mb4;

CREATE DATABASE IF NOT EXISTS `gakumas_sms` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;
USE `gakumas_sms`;

SET @OLD_FOREIGN_KEY_CHECKS=@@FOREIGN_KEY_CHECKS;
SET FOREIGN_KEY_CHECKS=0;
START TRANSACTION;

-- Clear existing sample data first to prevent duplicate primary-key import errors
DELETE FROM `student_songs`;
DELETE FROM `daily_student_stats`;
DELETE FROM `producer_messages`;
DELETE FROM `recurring_schedules`;
DELETE FROM `students`;
DELETE FROM `teachers`;
DELETE FROM `songs`;
DELETE FROM `users`;

-- Import parent tables first
-- Data for table `users`

-- Data for table `teachers`

-- Data for table `students`

-- Data for table `songs`

-- Data for table `student_songs`

-- Data for table `daily_student_stats`

-- Data for table `producer_messages`

-- Data for table `recurring_schedules`

-- Move AUTO_INCREMENT counters after the imported IDs
ALTER TABLE `users` AUTO_INCREMENT = 18;
ALTER TABLE `teachers` AUTO_INCREMENT = 4;
ALTER TABLE `students` AUTO_INCREMENT = 14;
ALTER TABLE `songs` AUTO_INCREMENT = 4;
ALTER TABLE `student_songs` AUTO_INCREMENT = 4;
ALTER TABLE `daily_student_stats` AUTO_INCREMENT = 161;
ALTER TABLE `producer_messages` AUTO_INCREMENT = 418;
ALTER TABLE `recurring_schedules` AUTO_INCREMENT = 313;

COMMIT;
SET FOREIGN_KEY_CHECKS=@OLD_FOREIGN_KEY_CHECKS;
